#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv0 = vUv;
vec2 sunpos = vec2 (rand_preset.x-.5,-.6);
vec3 suncol = vec3 (.9,.6,.5);

vUv -= 0.5;
vUv *= uAspect.xy;
vUv.x = vUv.x / (1+0*vUv.y); //Perspektive


//Himmel
vec3 clouds = clamp01(pow(uv0.y,2)) * (1+rand_preset);
clouds += clamp01(1-uv0.y)  * (1+rand_preset*slow_roam_cos)/2;

//Sonne
vec3 sun = clamp01(.01/length(vUv-sunpos))*suncol;

anz = 6; cover = 0; ret1 = 0;
//Baum
for (n=1;n<=anz;n++) {
    dist = 1-fract(1.0*n/anz+.02*uTime);
    dist2 = 1-fract(1.0*n/anz+.01*uTime);

    inten = (1-dist)*2;
    uv2.y = vUv.y-.2*rand_preset.y ;
    uv2.x = vUv.x + (rand_preset.z-.5)/2 ;
    uv2 = (1+2*rand_preset.x)*
    dist*uv2-vec2(0.5,.25+q10+.1*rand_preset.x); //Blickpunkt vert.
    uv3 = fract(uv2) ;

    uv5 = normalize(vec2(vUv.x,vUv.y)-sunpos)*.2+sunpos;
    cover += lum(GetBlur1(fract(2*uv5*dist2)));

    neu = (texture(sampler_main,uv3)+GetBlur1(uv3))/4;
    ret1 = ret1 + neu*inten;
//n++;
}

ray = clamp01(cover*2);
//ray *= clamp01(1-sun*2);
//ray = clamp01(ray);


ret = clamp01( clouds) ;
ret *= (.4+ray*ray*.8)*1.5;
ret *= clamp01(1-ret1.r*4);
ret += ray*.1*rand_preset.x*(1+rand_preset)*(vUv.y+.5);

  fragColor = ret;
}
